-- =====================================================
-- CREATE DATABASE (Optional)
-- =====================================================

CREATE DATABASE gold_db;
GO

USE gold_db;
GO

-- DATA SOURCE pointing to ADLS Gen2
CREATE EXTERNAL DATA SOURCE MyDataLake
WITH (
    LOCATION = 'https://ckrsynstorage.dfs.core.windows.net/gold'
);

--drop external data source MyDataLake2

CREATE EXTERNAL DATA SOURCE MyDataLake2
WITH (
    LOCATION = 'https://ckrsynstorage.dfs.core.windows.net/'
);


-- Delta format definition
CREATE EXTERNAL FILE FORMAT DeltaFormat
WITH (
    FORMAT_TYPE = DELTA
);


CREATE EXTERNAL FILE FORMAT parquet_format
WITH (
    FORMAT_TYPE = PARQUET
);
